            best_dx, best_dy = dx, dy

    # Fallback to move toward target if no safe move found
    if best_score is None:
        dx = tx - mx
        dy = ty - my
        if dx != 0:
            dx = int(dx/abs(dx))
        else:
            dx = 0
        if dy != 0:
            dy = int(dy/abs(dy))
        else:
            dy = 0
        nx, ny = mx + dx, my + dy
        if safe(nx, ny):
            best_dx, best_dy = dx, dy
        else:
            best_dx, best_dy = 0, 0

    return [best_dx, best_dy]
